{"code": "import json
from collections import Counter

# Load the data from previous queries
cases_data = locals()['var_functions.query_db:6']
order_items_data = locals()['var_functions.query_db:8']

# Normalize IDs by removing leading #
order_item_ids = set()
for item in order_items_data:
    item_id = item['Id']
    # Remove leading # if present
    if item_id.startswith('#'):
        item_id = item_id[1:]
    order_item_ids.add(item_id)

# Find cases related to this product (matching orderitemid__c)
# Also normalize case orderitemid__c by removing leading #
product_cases = []
for case in cases_data:
    case_orderitem_id = case['orderitemid__c']
    if case_orderitem_id:
        if case_orderitem_id.startswith('#'):
            case_orderitem_id = case_orderitem_id[1:]
        if case_orderitem_id in order_item_ids:
            product_cases.append(case)

# Count occurrences of each issueid__c
issue_counts = Counter()
for case in product_cases:
    if case['issueid__c']:
        issue_counts[case['issueid__c']] += 1

# Find the most common issue
most_common_issue = None
if issue_counts:
    most_common_issue = issue_counts.most_common(1)[0][0]

# Print the result in the required format
print('__RESULT__:')
print(json.dumps({
    'most_common_issue': most_common_issue,
    'total_matching_cases': len(product_cases),
    'issue_counts': dict(issue_counts),
    'total_order_items': len(order_item_ids)
}))"}
